var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. TPM002M000140-01: <color=#ffd34c>이유미</color>","JPN":"NETBLINK SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION：<color=#ffd34c>CONFIRMED</color>\\nCCN No. TPM002M000140-01：<color=#ffd34c>カスカベ・ユミ</color>","ENG":"[[","TWN":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No.TPM002M000140-01: <color=#ffd34c>李悠美</color>","THA":"ระบบรักษาความปลอดภัยเน็ตบลิงค์: <color=#ffd34c>ทำงาน</color>\\nระบุตัวตน: <color=#ffd34c>ยืนยัน</color>\\nCCN หมายเลข TPM002M000140-01: <color=#ffd34c>ลี ยูมี</color>","VTN":"TRÌNH TỰ AN NINH NETBLINK: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>\\nMÃ ĐỊNH DANH: <color=#ffd34c>ĐÃ XÁC NHẬN</color>\\nCCN Số TPM002M000140-01: <color=#ffd34c>Lee Yumi</color>","SCN":"NETBLINK 安全序列: <color=#ffd34c>激活</color>\\n身份ID: <color=#ffd34c>已确认</color>\\nCCN No.TPM002M000140-01: <color=#ffd34c>李悠悠</color>","DEU":"NETBLINK SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>\\nIDENTIFIZIERUNG: <color=#ffd34c>BESTÄTIGT</color>\\nCCN-Nr. TPM002M000140-01: <color=#ffd34c>Lee Yumi</color>","FRA":"PROTOCOLE DE SÉCURITÉ NETBLINK\xA0: <color=#ffd34c>ACTIVÉ</color>\\nIDENTIFICATION\xA0: <color=#ffd34c>CONFIRMÉE</color>\\nCCN No. TPM002M000140-01\xA0: <color=#ffd34c>Lee Yumi</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"그럼 마지막 질문입니다.","JPN":"では、最後の質問です。","ENG":"Okay, last question.","TWN":"那這是最後一個問題。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"이유미 씨는 정의가 무엇이라고 생각하십니까?","JPN":"カスカベ・ユミさんが思う正義は何ですか？","ENG":"What does justice mean to you, Ms. Lee?","TWN":"對悠美小姐來說，正義是什麼？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아주 쉬운 질문이군요.","JPN":"とても簡単な質問ですね。","ENG":"That's an easy one.","TWN":"這問題太簡單了。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"정의란 악을 심판하는 것입니다.","JPN":"正義とは悪を裁くことです。","ENG":"Justice is bringing judgment upon evil.","TWN":"正義就是制裁邪惡。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"철저하고 무자비하게 범죄자를 뿌리 뽑는 것만이 정의라고 할 수 있습니다.","JPN":"徹底的かつ無慈悲に犯罪者を滅ぼすことのみが正義だと思います。","ENG":"Justice means thoroughly and mercilessly eradicating all crime.","TWN":"只有徹底地將罪犯無情根除，才能稱之為是正義。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"음...... 그렇군요. 알겠습니다.","JPN":"うむ……そうですか。わかりました。","ENG":"Hmm... I see. Duly noted.","TWN":"呃……原來如此，我知道了。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"면접결과는 추후에 통보해드리도록 하겠습니다.","JPN":"面接結果は後ほどお知らせします。","ENG":"We'll be in touch regarding your interview results.","TWN":"面試的結果會在之後會通知您。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"정말 괜찮을까요?","JPN":"本当に大丈夫でしょうか？","ENG":"Are you sure about this?","TWN":"真的沒問題嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"아무리 최근에 경찰 지원자가 부족하다지만 이 정도로 기본 소양이 부족한 사람을 채용하는 건 문제가 될 수도 있습니다.","JPN":"いくら最近警察志願者が減ってきているとしても、これほど基本的な職業素養が足りない者を採用するのは問題になるかもしれません。","ENG":"I know we've been short on applicants lately, but hiring someone with such an unfit ideology could prove problematic for the force later.","TWN":"就算最近的警察志願者不足，但聘用這種缺乏基本素養的人會出問題吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"어쩔 수 없지. 자네 말대로 인력이 너무 부족해.","JPN":"仕方ないんだ。君の言うとおり、警察は深刻な人手不足に直面している。","ENG":"We don't really have a choice. As you've said, we're really short on manpower.","TWN":"沒辦法啊。就像你說的一樣，最近實在是太缺人手了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"이미 공권력의 대부분이 군대에서 민간군사기업 쪽으로 넘어간 게 현실이야.","JPN":"すでに主な公権力が軍から民間軍事企業の手に墜ちたのが現実だ。","ENG":"It doesn't help that a lion's share of law enforcement personnel transferred over to private military companies already.","TWN":"現在的公權力已經從軍方轉移到私人軍事公司了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"변화가 없다면 치안 유지마저 경찰의 손에서 떠날 수도 있네.","JPN":"変化がないと、治安維持さえも警察の手を離れるかもしれない。","ENG":"If we can't change that, the police may lose its responsibility for maintaining law and order.","TWN":"如果沒有改變的話，警察可能連維護治安的權力都會失去。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"그런 건 용납할 수 없어.","JPN":"そんなことは許せない。","ENG":"I will not let it ever come to that if I can help it.","TWN":"我無法忍受這種事情發生。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"거기다가 자발적으로 지원한 카운터 능력자 아닌가?","JPN":"それに、自ら志願したカウンター能力者ではないか。","ENG":"Besides, this is a Counter who voluntarily applied.","TWN":"而且她還是自願來幫忙的制裁者啊？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"이번 기회를 놓치면 다음 카운터 채용이 언제일지는 기약도 없으니까.","JPN":"このチャンスを逃したら、次のカウンター採用がいつになるかわからないしな。","ENG":"If we miss our chance now, there's no telling when we'll be able to hire another one.","TWN":"如果錯過這次機會，下次能錄用制裁者不知道要等到什麼時候。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"하지만 그래도......","JPN":"ですが……","ENG":"But still...","TWN":"但就算這樣……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};